external_knowledge:
- 'Gmail authors' refers to authors whose email addresses end with '@gmail.com'; 
- '10%-royalty books' means books with a royalty rate of '10%'; 
- 'seasoned researchers' refers to researchers with more than 5 years of experience.

sql:
SELECT 
    (SELECT title FROM books WHERE price = (SELECT MAX(price) FROM books)) AS most_expensive_book,
    (SELECT SUM(num_pages) FROM books) AS total_pages;

SELECT 
  FLOOR(AVG(CAST(REPLACE(REPLACE(revenue, '$', ''), ',', '') AS REAL))) AS average_revenue
FROM book_sales;

SELECT DISTINCT firstname, middlename, lastname, email
FROM authors
ORDER BY email ASC;
